import React from 'react';
import { useNavigate } from 'react-router-dom';
import { Button, Typography } from 'antd';
import { IdcardOutlined, QuestionCircleOutlined, UnorderedListOutlined } from '@ant-design/icons';

import { HeaderType } from '../../models/HeaderType';
import SearchInput from '../SearchInput';
import classes from './Header.module.scss';

import 'antd/dist/antd.css';

const Header: React.FC<HeaderType> = (props) => {
  const {
    searchInputHandler, inputValue, filtered, showSearch,
  } = props;

  const navigate = useNavigate();

  const { Title } = Typography;

  return (
    <div className={classes.header}>
      <Title style={{ width: '100%', textAlign: 'center' }}>This uses the Rick and Morty API</Title>
      <nav>
        <ul className={classes.nav}>
          <li><Button style={{ marginRight: 5 }} type="primary" onClick={() => { navigate('/about'); }}> <QuestionCircleOutlined />About</Button></li>
          <li><Button style={{ marginRight: 5 }} onClick={() => { navigate('/list'); }}><UnorderedListOutlined />List</Button></li>
          <li><Button onClick={() => { navigate('/cards'); }}> <IdcardOutlined />Cards</Button></li>
        </ul>
      </nav>
      {showSearch
        && (
          <><label className={classes.label} htmlFor="searchInput">Search character</label>
            <br />
            <SearchInput name="searchInput" searchInputHandler={searchInputHandler} inputValue={inputValue} filtered={filtered} />
          </>
        )}

    </div>
  );
};

export default Header;
