import { Avatar, List } from 'antd';
import React from 'react';
import { Link } from 'react-router-dom';

import { CharacterListType } from '../../../models/CharacterListType';

const CharacterList: React.FC<CharacterListType> = (props) => {
  const data = props.filtered;
  return (
    <>
      <List
        itemLayout="horizontal"
        dataSource={data}
        renderItem={(item) => (
          <List.Item>
            <List.Item.Meta
              avatar={<Avatar src={item.image} />}
              title={<Link to={`/single/${item.id}`}>{item.name}</Link>}
              description={item.type ? item.type : 'Common'}
            />
            <Link to={`/single/${item.id}`} />
          </List.Item>
        )}
      />
    </>
  );
};

export default CharacterList;
