import axios from 'axios';
import { makeAutoObservable } from 'mobx';

import { CharacterType } from '../models/CharacterType';

class CharactersStore {
  characters: CharacterType[] = []; // Персонажи

  filtered: CharacterType[] = []; // Отфильтрованные персонажи

  loading = true;

  inputValue = ''; // Строка поиска

  getCharacters = (): void => {
    axios('https://rickandmortyapi.com/api/character')
      .then((res) => this.setCharacters(res.data.results))
      .then(() => { this.setLoading(false); });
  };

  setCharacters = (newCharacters: CharacterType[]): void => {
    this.characters = newCharacters;
  };

  setFiltered = (newFiltered: CharacterType[]): void => {
    this.filtered = newFiltered;
  };

  setInputValue = (newinputValue: string): void => {
    this.inputValue = newinputValue;
  };

  setLoading = (newLoading: boolean): void => {
    this.loading = newLoading;
  };

  filterCharacters = () => {
    if (this.inputValue.length > 2) {
      this.setFiltered(this.characters
        .filter((character) => character.name.toLocaleLowerCase().includes(this.inputValue)));
    } else {
      this.setFiltered(this.characters);
    }
  };

  constructor() {
    makeAutoObservable(this);
    this.getCharacters();
  }
}

export const store = new CharactersStore();
