import React, { ReactElement, useEffect, useState } from 'react';
import { observer } from 'mobx-react-lite';
import { useLocation } from 'react-router-dom';

import AppRouter from '../AppRouter';
import Err from '../Err';
import Header from '../Header';
import NoResults from '../NoResults';
import Preloader from '../Preloader';
/* import Preloader from '../Preloader'; */
import classes from './App.module.scss';
import { store } from '../../stores/store';

const App: React.FC = observer(() => {
  /*   const [loading, setLoading] = useState<boolean>(true); */
  const [showSearch, setShowSearch] = useState<boolean>(true);

  const {
    characters, loading, filtered, inputValue, setInputValue, filterCharacters,
  } = store;

  /*   const getCharacters = (): void => {
      fetch('https://rickandmortyapi.com/api/character')
        .then((res) => res.json())
        .then((data) => setCharacters(data.results))
        .then(() => { setLoading(false); });
    };
    useEffect(() => {
      getCharacters();
    }, []); */

  useEffect(() => {
    filterCharacters();
  }, [characters, inputValue]); // Фильтрация работает при изменении стейта со всеми персонажами (при загрузке страницы) и при изменении в строке поиска

  const { pathname } = useLocation();

  useEffect(() => { // Скрываем строку поиска там, где она не нужна
    if (pathname === '/about' || pathname.includes('/single/')) {
      setShowSearch(false);
    } else {
      setShowSearch(true);
    }
  }, [filtered, pathname]); // Проверяем только при монтировании, изменении filtered и при переходах по страницам

  const searchInputHandler = (event: React.ChangeEvent<HTMLInputElement>) => {
    setInputValue(event.target.value);
  };

  const checksTheResult = (): null | ReactElement => {
    if (!filtered.length) {
      return <NoResults />;
    }
    return null;
  };

  try {
    return (
      <>
        <div className={classes.container}>
          <Header
            searchInputHandler={searchInputHandler}
            inputValue={inputValue}
            filtered={filtered.length}
            showSearch={showSearch}
          />
          {loading ? <Preloader /> : <AppRouter filtered={filtered} />}
          {checksTheResult()} {/* // Если нет совпадений при поиске, показываем компонент NoResults */}
        </div>
      </>
    );
  } catch {
    return <Err />; // Если при рендере компонента возникнет ошибка, рендерим компоненнт ошибки вместо контента
  }
});

export default App;
